#!/usr/bin/env bash
# Generated by test-suite-generator/0.1.0
# Threshold pulled from done_when.yaml: mutation_kill_rate >= 0.70
#
# This script runs the mutation test suite for channel-mention-notifications
# and exits nonzero if kill rate drops below 70%. ratchet relies on the exit
# code as the "not done" signal — do NOT lower the threshold to make this
# pass; instead, look at the surviving mutants and write the assertions
# they reveal.

set -euo pipefail

THRESHOLD=70  # percent — matches done_when.yaml mutation_kill_rate

echo "Running mutmut against src/notifications/ ..."
mutmut run

# Parse mutmut results
RESULT=$(mutmut results | tail -1)
KILLED=$(echo "$RESULT" | grep -oP 'killed:\s*\K\d+' || echo 0)
SURVIVED=$(echo "$RESULT" | grep -oP 'survived:\s*\K\d+' || echo 0)
TIMEOUT=$(echo "$RESULT" | grep -oP 'timeout:\s*\K\d+' || echo 0)
SUSPICIOUS=$(echo "$RESULT" | grep -oP 'suspicious:\s*\K\d+' || echo 0)
TOTAL=$(( KILLED + SURVIVED + TIMEOUT + SUSPICIOUS ))

if [[ $TOTAL -eq 0 ]]; then
  echo "ERROR: mutmut produced no mutants — config likely wrong."
  echo "Check paths_to_mutate and runner settings in pyproject.toml."
  exit 1
fi

SCORE=$(( (KILLED + TIMEOUT) * 100 / TOTAL ))
echo "─────────────────────────────────"
echo "Kill rate: $SCORE% ( (killed=$KILLED + timeout=$TIMEOUT) / total=$TOTAL )"
echo "Survived: $SURVIVED · Suspicious: $SUSPICIOUS"

if [[ $SCORE -lt $THRESHOLD ]]; then
  echo "✗ Below threshold $THRESHOLD% — surviving mutants:"
  mutmut results | grep -E '^(survived|timeout)' | head -30 || true
  echo ""
  echo "Each surviving mutant pinpoints an assertion gap. Add the missing"
  echo "assertion to the test that already covers the line, then re-run."
  exit 1
fi

echo "✓ Kill rate $SCORE% above $THRESHOLD%"
